-- Apex Advantage — DPE Question Bank Expansion, Batch 5 (v35)
--
-- Adds 72 new oral-exam questions sourced from the "Apex Advantage Checkride
-- Prep Supplement" — eight new questions per existing core section, mapped
-- to the ACS, continuing on past the 256-question bank established by
-- v10 through v13. Two categories (aeromedical, emergency) receive their
-- first expansion since the original v5 launch content; the other seven
-- categories continue their existing id/sort_order numbering from v10-v13.
--
-- Final category counts after this batch:
--   eligibility        28   airspace           38
--   airworthiness       28   weather            38
--   privileges          38   performance        28
--   crosscountry        33   aeromedical        16
--   emergency           16   aircraft-systems   25  (unchanged)
--   adm                 40  (unchanged)
--   ------------------------------------------------
--   TOTAL              328
--
-- Run this in the Supabase SQL editor, after supabase-portal-schema-v34.

insert into public.dpe_questions (id, category, question, model_answer, common_mistakes, dpe_evaluating, acs_reference, real_world_application, is_scenario, scenario_order, sort_order) values
  -- ═════════════════════ ELIGIBILITY, extending to 28 (+8) ═════════════════════

  ('elig-21', 'eligibility', 'What are the aeronautical experience (flight hour) requirements to be eligible for a Private Pilot Certificate under Part 61?', 'At least 40 hours of total flight time, including 20 hours of flight training with an instructor (with specific requirements for cross-country, night, instrument, and test-prep time) and 10 hours of solo flight (including a solo cross-country of at least 150 nautical miles total distance with landings at three points more than 50 nautical miles apart, plus 5 hours of solo cross-country time overall and required solo airport operations).', 'Forgetting the specific 150-nautical-mile, three-point solo cross-country requirement, or confusing it with the general 5-hour solo cross-country minimum.', 'Whether the applicant''s own logbook actually satisfies these minimums — not just general familiarity with the number 40.', 'Area of Operation I, Task A — Pilot Qualifications (Knowledge).', 'The examiner will cross-check these totals directly against the applicant''s logbook during the document review portion of the exam.', false, null, 20),
  ('elig-22', 'eligibility', 'What is required for a non-U.S. citizen to pursue flight training in the United States?', 'Citizenship does not bar certification, but non-U.S. citizens must comply with the TSA Flight Training Security Program (49 CFR Part 1552), which requires a TSA background check and approval before certain flight training can begin.', 'Assuming citizenship status has no bearing on the training process at all, when TSA compliance is a real, separate prerequisite step.', 'Basic awareness that this additional regulatory layer exists, particularly relevant for flight schools training international students.', 'Area of Operation I, Task A — Pilot Qualifications (Knowledge).', 'Directly relevant to any flight school, including Apex Aviation, that trains international students.', false, null, 21),
  ('elig-23', 'eligibility', 'Does a student pilot certificate expire, and how does that differ from solo endorsement currency?', 'The current plastic student pilot certificate (issued since April 2016) does not expire on its own. However, solo flight privileges require a current, separate solo endorsement from an instructor that must be renewed every 90 calendar days.', 'Confusing the certificate''s non-expiring status with the 90-day solo endorsement, which does require renewal.', 'Whether the applicant separates certificate validity from the ongoing endorsement requirement that governs actual solo privileges.', 'Area of Operation I, Task A — Pilot Qualifications (Knowledge).', 'Relevant for a student who has taken time off training and needs to know exactly what has and hasn''t lapsed.', false, null, 22),
  ('elig-24', 'eligibility', 'What is the difference between a medical certificate being deferred versus denied?', 'A deferral means the Aviation Medical Examiner forwards the applicant''s file to the FAA for further review rather than issuing on the spot; a denial means the FAA has determined the applicant does not currently meet medical standards, though special issuance or reconsideration may still be available.', 'Treating a deferral as equivalent to a denial, when a deferral simply means a decision hasn''t been made yet.', 'Understanding of the AME''s limited authority versus the FAA''s final decision-making authority.', 'Area of Operation I, Task A — Pilot Qualifications (Knowledge).', 'Relevant for any applicant with a disclosed medical history — knowing this distinction reduces unnecessary anxiety during the medical exam.', false, null, 23),
  ('elig-25', 'eligibility', 'What is a Special Issuance medical certificate?', 'An FAA-authorized medical certificate issued to an applicant who does not meet the standard medical requirements outright but demonstrates the condition is adequately controlled, typically requiring periodic follow-up reports under 14 CFR 67.401.', 'Assuming any disqualifying medical condition permanently bars certification, when a special issuance pathway may still exist.', 'Awareness that certification pathways exist beyond an outright denial.', 'Area of Operation I, Task A — Pilot Qualifications (Knowledge).', 'Many career pilots fly for decades under special issuance for well-managed conditions — this pathway matters beyond the checkride.', false, null, 24),
  ('elig-26', 'eligibility', 'How do you replace a lost or destroyed pilot certificate?', 'Request a replacement through IACRA (or by mail with the appropriate fee to the FAA Airmen Certification Branch); a temporary authority to exercise certificate privileges can often be printed from IACRA while the physical replacement is processed.', 'Believing certificate privileges cannot be exercised at all until the physical card arrives, without checking for a temporary IACRA authority.', 'Practical, real-world familiarity with the FAA''s airman services process.', 'Area of Operation I, Task A — Pilot Qualifications (Knowledge).', 'Useful lifetime knowledge for any pilot, not just checkride trivia.', false, null, 25),
  ('elig-27', 'eligibility', 'What specific night flight experience is required for Private Pilot certification (as distinct from night currency)?', 'Three hours of night flight training, including one cross-country flight over 100 nautical miles total distance, and 10 night takeoffs and landings to a full stop.', 'Confusing this one-time certification requirement with the ongoing night currency requirement (three takeoffs and landings within the preceding 90 days) covered elsewhere in this guide.', 'Whether the applicant clearly distinguishes certification minimums from ongoing currency requirements.', 'Area of Operation I, Task A — Pilot Qualifications (Knowledge).', 'Applicants who train mostly during long summer days sometimes have to specifically schedule this requirement late in training.', false, null, 26),
  ('elig-28', 'eligibility', 'What common errors in the IACRA application process cause checkride delays?', 'Mismatched personal information between IACRA and the applicant''s photo ID, missing or incomplete instructor endorsements and signatures, and an improperly set up FTN (FAA Tracking Number) are among the most common, entirely avoidable delays.', 'Waiting until the day before the checkride to complete the IACRA application, leaving no time to correct an error.', 'Whether the applicant treated this administrative process seriously and well in advance of the exam.', 'Area of Operation I, Task A — Pilot Qualifications (Knowledge).', 'Complete and review your IACRA application at least a week before your scheduled checkride, not the night before.', false, null, 27),
  -- ═════════════════════ AIRWORTHINESS, extending to 28 (+8) ═════════════════════

  ('aw-21', 'airworthiness', 'What is a Type Certificate Data Sheet (TCDS), and why does it matter for airworthiness?', 'The TCDS is the FAA document defining an aircraft''s approved design — including approved engine and propeller combinations, weight limits, and equipment. It''s the baseline against which "conformity to type design," one half of the legal definition of airworthiness, is measured.', 'Not realizing that any modification must be traceable to the TCDS or an approved Supplemental Type Certificate to remain legal.', 'Whether the applicant connects the TCDS directly to the two-part airworthiness definition covered earlier in this section.', 'Area of Operation I, Task B — Airworthiness Requirements (Knowledge).', 'Relevant any time you''re evaluating whether an aftermarket modification on an aircraft you''re flying is actually legal.', false, null, 20),
  ('aw-22', 'airworthiness', 'What is a Supplemental Type Certificate (STC), and how does it affect an aircraft''s airworthiness?', 'An STC approves a major modification to an aircraft''s original type design — such as an avionics upgrade or engine conversion. The modified aircraft remains airworthy only if the modification was installed per the STC and is properly documented in the maintenance records.', 'Assuming any popular aftermarket part is automatically legal to install without STC or PMA approval.', 'Whether the applicant understands an STC modifies, rather than replaces, the original TCDS baseline.', 'Area of Operation I, Task B — Airworthiness Requirements (Knowledge).', 'Owners frequently install STC''d avionics like the Garmin G5 — know how to verify the paperwork supports the installation.', false, null, 21),
  ('aw-23', 'airworthiness', 'What is a life-limited part, and how does it differ from a part maintained on-condition?', 'A life-limited part has a mandatory replacement interval, defined in flight hours, cycles, or calendar time, regardless of its physical condition. A part maintained on-condition is instead replaced only when it fails inspection or a functional check.', 'Assuming all maintenance is on-condition, missing that certain components must be replaced on a hard schedule regardless of apparent wear.', 'Whether the applicant distinguishes hard-time maintenance from on-condition maintenance as two genuinely different concepts.', 'Area of Operation I, Task B — Airworthiness Requirements (Knowledge).', 'Less prominent in simple trainers but critical for pilots moving toward complex or turbine aircraft ownership.', false, null, 22),
  ('aw-24', 'airworthiness', 'How often must a VOR be checked for accuracy for IFR use, and what methods are acceptable?', 'Every 30 days, per 14 CFR 91.171. Acceptable methods include a VOT test facility (±4° tolerance), a certified ground checkpoint (±4°), a certified airborne checkpoint (±6°), or a dual VOR cross-check between two receivers (must agree within 4° of each other). The date, place, error, and a signature must be logged.', 'Mixing up the tolerance for each method, or forgetting that the check result must actually be logged with the required details.', 'Precise recall of both the specific tolerances and the logging requirement — a favorite live-recitation question.', 'Area of Operation I, Task B — Airworthiness Requirements (Knowledge). Cross-references Area IX, Task A.', 'This exact question is popular with examiners because it combines a regulation with a real logbook entry requirement.', false, null, 23),
  ('aw-25', 'airworthiness', 'How long must aircraft maintenance records generally be retained?', 'Records showing total time in service must be retained until superseded or for one year, whichever is longer; records of current status for life-limited parts and Airworthiness Directive compliance must be retained until the item is replaced or the AD is next complied with; records of the most recent annual or 100-hour inspection are generally kept until superseded by the next one.', 'Assuming all maintenance records must be kept indefinitely, or discarding AD compliance records prematurely.', 'Whether the applicant understands records retention isn''t a single uniform rule across every record type.', 'Area of Operation I, Task B — Airworthiness Requirements (Knowledge).', 'Directly relevant to any pilot evaluating an aircraft''s maintenance history before purchase or a long-term rental commitment.', false, null, 24),
  ('aw-26', 'airworthiness', 'What is the owner or operator''s specific maintenance responsibility under 14 CFR 91.403?', 'The owner or operator is primarily responsible for keeping the aircraft in an airworthy condition, including compliance with Airworthiness Directives, and for ensuring maintenance is properly recorded — a duty that exists independent of and in addition to any mechanic''s work.', 'Assuming this responsibility shifts entirely to the mechanic once maintenance work is performed and signed off.', 'Whether the applicant, especially as a future aircraft owner, understands this is a non-delegable duty.', 'Area of Operation I, Task B — Airworthiness Requirements (Knowledge).', 'Relevant the moment a pilot becomes an owner, and even for renters evaluating an aircraft before a flight.', false, null, 25),
  ('aw-27', 'airworthiness', 'What is a Special Flight Permit (ferry permit), and when is it used?', 'A Special Flight Permit authorizes flight of an aircraft that does not currently meet airworthiness requirements, for a narrow, defined purpose — such as flying to a maintenance base for repair — issued by the FAA with specific conditions and an approved route.', 'Assuming an unairworthy aircraft can never legally be flown under any circumstances whatsoever.', 'Awareness that a narrow, controlled legal pathway exists for an otherwise-unairworthy aircraft.', 'Area of Operation I, Task B — Airworthiness Requirements (Knowledge).', 'Relevant if an aircraft is found unairworthy while away from its home maintenance facility.', false, null, 26),
  ('aw-28', 'airworthiness', 'What logging requirement applies when a pilot performs their own allowed preventive maintenance?', 'The pilot must make a maintenance record entry describing the work performed, along with the date and their name, certificate number, and certificate type, signed as the person approving the aircraft for return to service.', 'Performing legally allowed preventive maintenance but failing to log it, which leaves the aircraft''s airworthiness status undocumented.', 'Whether the applicant understands that documentation is part of the privilege itself, not an optional extra step.', 'Area of Operation I, Task A / I, Task B — Pilot Qualifications and Airworthiness Requirements (Knowledge).', 'Connects directly to the preventive maintenance privilege discussed in Section 4 — examiners like linking these two topics.', false, null, 27),
  -- ═════════════════════ PRIVILEGES / REGULATIONS, extending to 38 (+8) ═════════════════════

  ('priv-31', 'privileges', 'Can a private pilot legally fly in formation with other aircraft?', 'Formation flight is prohibited except by prior arrangement with the pilot in command of each aircraft in the formation, per 14 CFR 91.111. It is not gated by a specific certificate or rating — mutual agreement and separation planning are the controlling requirements.', 'Believing formation flight requires ATC permission alone, rather than pilot-to-pilot arrangement first.', 'Whether the applicant knows agreement between pilots, not certification level, is the controlling legal requirement.', 'Area of Operation I, Task A — Pilot Qualifications (Knowledge).', 'Directly relevant to group fly-outs and formation arrivals common among private pilot communities.', false, null, 30),
  ('priv-32', 'privileges', 'What additional training is required to act as PIC of a high-performance, complex, or tailwheel airplane?', 'A logbook endorsement from an authorized instructor certifying the pilot received and demonstrated proficiency in the applicable ground and flight training, per 14 CFR 61.31 — for high-performance (over 200 horsepower), complex (retractable gear, flaps, and controllable-pitch propeller), or tailwheel airplanes.', 'Believing a separate certificate or rating, rather than a simple logbook endorsement, is required for these categories.', 'Whether the applicant knows this privilege is endorsement-based, not an added certificate or rating.', 'Area of Operation I, Task A — Pilot Qualifications (Knowledge).', 'Relevant the first time a private pilot wants to step up to a more capable rental or personal airplane.', false, null, 31),
  ('priv-33', 'privileges', 'Can a private pilot log instrument time, and under what conditions?', 'Yes — a pilot may log instrument time, actual or simulated, any time they operate solely by reference to instruments, whether or not the flight is conducted under an IFR flight plan. Simulated instrument time under VFR requires a qualified safety pilot in the other seat.', 'Believing instrument time can only be logged while actually operating under an IFR clearance.', 'Whether the applicant separates the act of logging instrument time from the act of flying under IFR.', 'Area of Operation I, Task A — Pilot Qualifications (Knowledge).', 'Relevant for private pilots beginning to build instrument experience even before pursuing an instrument rating.', false, null, 32),
  ('priv-34', 'privileges', 'What are the requirements to act as a safety pilot for another pilot''s simulated instrument practice?', 'The safety pilot must hold at least a private pilot certificate with the appropriate category and class rating for the aircraft being flown, and the aircraft must have functioning dual controls; the safety pilot is responsible for collision avoidance while the flying pilot is under the view-limiting device.', 'Assuming any certificated pilot can safety-pilot in any aircraft, regardless of their own category or class rating.', 'Precise knowledge of the category and class rating requirement specific to the safety pilot role.', 'Area of Operation I, Task A — Pilot Qualifications (Knowledge).', 'A common, mutually beneficial arrangement between private pilots working toward an instrument rating together.', false, null, 33),
  ('priv-35', 'privileges', 'What is generally required for a private pilot to add a new category or class rating?', 'Complete the required aeronautical experience and training specific to that category or class, receive an endorsement of preparedness from an authorized instructor, and in most cases pass the additional practical test — though many additional ratings do not require a new knowledge test.', 'Assuming a full new written knowledge test is always required, when most added ratings only require the additional practical test.', 'General familiarity with the added-rating process, useful for pilots planning to expand their privileges.', 'Area of Operation I, Task A — Pilot Qualifications (Knowledge).', 'Directly relevant to any pilot planning a multi-rating career path, including instrument, commercial, and beyond.', false, null, 34),
  ('priv-36', 'privileges', 'What operating limitations commonly apply to experimental category aircraft?', 'Experimental aircraft operate under specific operating limitations issued alongside their airworthiness certificate, often restricting flight over congested areas, carrying passengers for compensation, or requiring a defined flight-test area during an initial phase. These limitations vary by aircraft and must be reviewed individually.', 'Assuming all experimental aircraft share identical restrictions rather than checking the specific aircraft''s operating limitations document.', 'Whether the applicant knows to check the aircraft-specific document rather than relying on general assumptions.', 'Area of Operation I, Task B — Airworthiness Requirements (Knowledge).', 'Increasingly relevant given the popularity of experimental and amateur-built aircraft in general aviation today.', false, null, 35),
  ('priv-37', 'privileges', 'What is required for a private pilot to legally tow a glider or a banner?', 'A specific towing endorsement under 14 CFR 61.69, including ground and flight training in towing procedures, plus a minimum logged experience threshold in the applicable category and class — a distinctly separate privilege from general private pilot certification.', 'Assuming general private pilot privileges automatically include the authority to tow gliders or banners.', 'Awareness that towing is a distinctly endorsed, add-on privilege, not an automatic one.', 'Area of Operation I, Task A — Pilot Qualifications (Knowledge).', 'Relevant to pilots interested in glider operations or commercial banner-towing work later in their career.', false, null, 36),
  ('priv-38', 'privileges', 'Under what circumstances can a private pilot log Second-in-Command (SIC) time?', 'SIC time may be logged when the aircraft''s type certification requires more than one pilot, or when a specific operation legally requires two pilots. Simply occupying the right seat of a single-pilot-certificated aircraft does not qualify.', 'Believing any time spent in the right seat, regardless of aircraft type or requirement, counts as loggable SIC time.', 'Whether the applicant distinguishes a legally required SIC role from informal right-seat time.', 'Area of Operation I, Task A — Pilot Qualifications (Knowledge).', 'Relevant for pilots building experience in multi-crew-capable aircraft or working toward advanced certificates.', false, null, 37),
  -- ═════════════════════ AIRSPACE, extending to 38 (+8) ═════════════════════

  ('asp-31', 'airspace', 'What is the Mode C veil, and what equipment does it require?', 'The Mode C veil is generally the airspace within 30 nautical miles of a Class B primary airport''s center point, from the surface up to 10,000 feet MSL, requiring an operating Mode C transponder (and ADS-B Out where applicable) — even for aircraft merely transiting the area, not just those entering the Class B itself.', 'Believing the transponder requirement applies only once actually inside the Class B airspace, not the surrounding veil.', 'Whether the applicant recognizes the veil extends equipment requirements beyond the Class B boundary itself.', 'Area of Operation III, Task A — Airspace (Knowledge).', 'Relevant flying anywhere near a major Class B airport, even without any intention of entering the Class B airspace.', false, null, 30),
  ('asp-32', 'airspace', 'Where is ADS-B Out equipment required under 14 CFR 91.225?', 'Generally required in Class A, B, and C airspace; above 10,000 feet MSL (excluding airspace at and below 2,500 feet AGL); and within 30 nautical miles of a Class B primary airport (the Mode C veil), among certain other designated areas.', 'Believing ADS-B Out is required everywhere, or forgetting the exception for airspace at or below 2,500 feet AGL even above 10,000 feet MSL.', 'Precise boundaries of the requirement — not just a general sense that "it''s usually required."', 'Area of Operation III, Task A — Airspace (Knowledge).', 'Directly affects real cross-country route and altitude planning around major Class B and C airspace.', false, null, 31),
  ('asp-33', 'airspace', 'What is Special VFR, and what are its requirements?', 'Special VFR allows operation within the lateral boundaries of surface-level controlled airspace below normal VFR weather minimums, with an ATC clearance, remaining clear of clouds, and at least 1 statute mile flight visibility. It is not authorized at night unless the pilot is instrument rated and the aircraft is instrument equipped.', 'Believing Special VFR is automatically available on request, rather than an ATC-issued clearance subject to traffic and workload.', 'Understanding of both the specific visibility/cloud requirement and the night limitation together.', 'Area of Operation III, Task A — Airspace (Knowledge).', 'A genuinely useful tool for departing or arriving at a towered airport in marginal weather, used judiciously.', false, null, 32),
  ('asp-34', 'airspace', 'What is a VFR transition route through Class B airspace, and how does it differ from a VFR flyway?', 'A published transition route allows VFR traffic to cross specific Class B airspace under defined procedures, and generally still requires an ATC clearance. A VFR flyway is an advisory routing suggestion for avoiding busy airspace altogether and does not itself grant entry into the Class B.', 'Treating a flyway (advisory only) and a transition route (clearance-based) as interchangeable terms.', 'Whether the applicant reads sectional chart symbology correctly for the specific Class B airspace being discussed.', 'Area of Operation III, Task A — Airspace (Knowledge). Cross-references Area IX, Task A.', 'Extremely useful for VFR pilots flying near major metro Class B airspace without a full clearance into it.', false, null, 33),
  ('asp-35', 'airspace', 'What is a National Security Area (NSA), and how should a pilot respond to one?', 'An NSA is airspace with defined boundaries established for security or national interest reasons. Pilots are typically requested — not required — to voluntarily avoid flight through an NSA, though the FAA may make flight restrictions mandatory by regulation for a specific NSA when necessary.', 'Treating every NSA as automatically illegal to enter, when many are voluntary-avoidance rather than mandatory-restricted.', 'Whether the applicant distinguishes voluntary-avoidance airspace from genuinely prohibited or restricted airspace.', 'Area of Operation III, Task A — Airspace (Knowledge).', 'Always check NOTAMs before flying near an NSA, since its status can shift from voluntary to mandatory with little notice.', false, null, 34),
  ('asp-36', 'airspace', 'How do Restricted, Prohibited, and Warning Areas differ in their legal effect on a VFR pilot?', 'Restricted areas (e.g., "R-2508") require permission from the controlling agency to enter; Prohibited areas (e.g., "P-56") are never open to civil entry; Warning Areas (e.g., "W-386") extend beyond 3 nautical miles from the coast and indicate potential hazardous activity without a formal entry restriction for civil aircraft, though caution is strongly advised.', 'Treating a Warning Area the same as a Restricted Area, when a Warning Area carries no formal entry-permission requirement.', 'Whether the applicant distinguishes all three categories by both their legal effect and their identifying letter.', 'Area of Operation III, Task A — Airspace (Knowledge).', 'Coastal cross-country flights frequently cross Warning Areas — know the letter-code distinctions on sight.', false, null, 35),
  ('asp-37', 'airspace', 'How are the different classes of controlled airspace generally distinguished on a sectional chart?', 'Each airspace class uses a distinct chart symbology and line style — solid versus dashed boundary lines in different colors, along with shaded vignettes for airspace floors that don''t begin at the surface. Reading these correctly takes practiced, repeated familiarity with an actual sectional chart, not verbal description alone.', 'Relying only on a verbal description of airspace boundaries rather than practicing with a real sectional until recognition becomes instant.', 'Whether the applicant can identify airspace class directly from a chart placed in front of them.', 'Area of Operation III, Task A — Airspace (Knowledge). Cross-references Area IX, Task A.', 'Examiners frequently test this by pointing at a real chart during the oral exam, not by asking an abstract question.', false, null, 36),
  ('asp-38', 'airspace', 'What separation service does ATC provide within Class B airspace, and how does this relate to the entry requirement?', 'Within Class B airspace, ATC provides separation between all aircraft — VFR-to-VFR and VFR-to-IFR — which is part of why an explicit clearance, rather than mere radio communication, is required to enter.', 'Believing VFR aircraft self-separate within Class B the way they might in Class E or G airspace.', 'Whether the applicant connects the clearance requirement to the actual separation service being provided.', 'Area of Operation III, Task A — Airspace (Knowledge).', 'This separation service is a genuine safety benefit of Class B for VFR pilots, not just a bureaucratic hurdle.', false, null, 37),
  -- ═════════════════════ WEATHER, extending to 38 (+8) ═════════════════════

  ('wx-31', 'weather', 'What is the standard lapse rate, and how does atmospheric stability affect the weather that develops?', 'The standard lapse rate is approximately 2°C (3.5°F) per 1,000 feet, used as a baseline temperature-altitude relationship. A stable atmosphere resists vertical motion and is associated with stratus clouds, fog, and smoother air; an unstable atmosphere promotes vertical motion and is associated with cumulus buildups, showers, and turbulence.', 'Confusing which cloud types and flight conditions correspond to stable versus unstable air.', 'Whether the applicant correctly pairs the atmospheric condition with its typical weather signature.', 'Area of Operation II, Task A — Weather Information (Knowledge).', 'Reading the cloud types present on a given day gives a fast, genuinely useful real-time read on atmospheric stability.', false, null, 30),
  ('wx-32', 'weather', 'What is low-level wind shear, and what are its common sources?', 'A rapid change in wind speed and/or direction over a short distance, commonly caused by frontal boundaries, thunderstorm outflow or microbursts, temperature inversions, or terrain effects — especially hazardous during takeoff and landing.', 'Associating wind shear only with thunderstorms, missing frontal and temperature-inversion-related shear sources.', 'Whether the applicant can name a complete list of shear sources, not just the most dramatic one.', 'Area of Operation II, Task A — Weather Information (Knowledge).', 'Take PIREPs and tower wind-shear alerts seriously on approach — they''re your real-time defense against this hazard.', false, null, 31),
  ('wx-33', 'weather', 'What specifically defines a "ceiling" in aviation weather reporting?', 'A ceiling is the height above ground level of the lowest layer of clouds reported as broken, overcast, or an obscuration. A scattered layer, no matter how low, does not constitute a ceiling.', 'Counting a scattered cloud layer as a ceiling, which understates actual usable VFR conditions.', 'Precise application of the reporting definition when reading a real METAR''s sky condition group.', 'Area of Operation II, Task A — Weather Information (Knowledge).', 'Directly affects your go/no-go read of a real METAR before every flight.', false, null, 32),
  ('wx-34', 'weather', 'What specific criteria trigger a Convective SIGMET?', 'Issued for hazardous convective weather, including severe or embedded thunderstorms, a line of thunderstorms, or thunderstorms producing hail three-quarters of an inch or larger and/or wind gusts of 50 knots or greater over a wide area — valid for a relatively short, specific time window.', 'Treating any general thunderstorm mention in a forecast as Convective SIGMET-level, when the actual criteria are more severe and specific.', 'Whether the applicant knows this represents a distinctly higher severity threshold than a general thunderstorm forecast.', 'Area of Operation II, Task A — Weather Information (Knowledge). Cross-references Risk Management.', 'A Convective SIGMET affecting your route area is generally an automatic no-go for a non-deiced VFR trainer.', false, null, 33),
  ('wx-35', 'weather', 'What is the Graphical Forecast for Aviation (GFA), and how is it used in preflight planning?', 'The GFA is the FAA''s current web-based aviation weather tool that replaced the legacy textual Area Forecast, providing graphical depictions of ceiling and visibility, sky condition, and hazards by region and forecast period.', 'Looking specifically for an old-format textual "area forecast" product that no longer exists in that form, rather than using the current graphical tool.', 'Current, up-to-date familiarity with the actual products a pilot uses today, not outdated legacy products.', 'Area of Operation II, Task A — Weather Information (Knowledge).', 'This is the actual tool used during a real preflight weather briefing today, not a historical footnote.', false, null, 34),
  ('wx-36', 'weather', 'How do you determine the freezing level for a planned flight, and why does it matter?', 'The freezing level — where temperature reaches 0°C — can be found using the Winds and Temperatures Aloft forecast or the GFA''s icing products. It matters because visible moisture near or below the freezing level is where structural icing risk is highest.', 'Assuming the freezing level is a single fixed altitude rather than something that varies by location and time and must be checked for the specific planned route.', 'Whether the applicant connects freezing-level data directly to the icing-risk concepts discussed earlier in this section.', 'Area of Operation II, Task A — Weather Information (Knowledge, Risk Management).', 'Check the freezing level any time a flight might operate near or above it in visible moisture, even outside seasons pilots typically associate with icing.', false, null, 35),
  ('wx-37', 'weather', 'What is mountain wave turbulence, and where is it most likely to be encountered?', 'Mountain wave forms when strong wind flows perpendicular to a mountain ridge, creating oscillating wave patterns downwind that can produce severe turbulence and strong up- and downdrafts, sometimes indicated visually by lenticular clouds.', 'Assuming mountain wave risk is limited to the airspace directly over the ridge, when the strongest turbulence is often well downwind of it.', 'Whether the applicant recognizes lenticular clouds as a visual warning sign of mountain wave activity.', 'Area of Operation II, Task A — Weather Information (Knowledge, Risk Management).', 'Relevant to cross-country planning near mountainous terrain with strong winds aloft, even at a significant distance downwind.', false, null, 36),
  ('wx-38', 'weather', 'What is virga, and why can it be a deceptive weather sign?', 'Virga is precipitation that evaporates before reaching the ground, appearing as streaks hanging below a cloud base. It can be associated with strong, unpredictable downdrafts and gust fronts even though no rain actually reaches the surface.', 'Assuming virga indicates no surface-level hazard simply because no rain is actually falling at ground level.', 'Whether the applicant recognizes that a real outflow or gust-front hazard can still exist beneath virga despite its dry appearance.', 'Area of Operation II, Task A — Weather Information (Knowledge, Risk Management).', 'A visually deceptive phenomenon worth specifically pointing out and avoiding flying beneath.', false, null, 37),
  -- ═════════════════════ PERFORMANCE & WEIGHT/BALANCE, extending to 28 (+8) ═════════════════════

  ('perf-21', 'performance', 'What is the difference between empty weight, useful load, and maximum gross weight?', 'Empty weight is the aircraft''s weight including unusable fuel and full operating fluids, but without crew, passengers, baggage, or usable fuel. Useful load is the difference between maximum gross weight and empty weight, available for crew, passengers, baggage, and usable fuel. Maximum gross weight is the certificated maximum total weight allowed for flight.', 'Confusing "empty weight" with "basic empty weight," which may define fluid levels differently depending on the specific aircraft''s documentation convention.', 'Precise use of each term applied to the applicant''s actual training aircraft''s weight and balance report.', 'Area of Operation V, Task A — Performance and Limitations (Knowledge).', 'This is the foundational vocabulary underlying every real weight and balance calculation a pilot will ever perform.', false, null, 20),
  ('perf-22', 'performance', 'How is a moment calculated, and why does the reference datum matter?', 'Moment equals weight multiplied by arm, where arm is the horizontal distance from a reference datum. The datum is an arbitrary reference point defined by the aircraft manufacturer — a different datum location changes the numerical arm values but not the underlying physics.', 'Not knowing where a specific aircraft''s datum is actually located, which makes its published arm values meaningless without that reference point.', 'Whether the applicant can correctly perform this calculation using the actual aircraft they fly, not just recite the formula.', 'Area of Operation V, Task A — Performance and Limitations (Knowledge, Skill).', 'Often demonstrated live using the applicant''s own aircraft''s weight and balance data during the oral exam.', false, null, 21),
  ('perf-23', 'performance', 'What is the difference between the graph method and the table method for computing weight and balance?', 'The graph method plots weight against moment or index on a chart to visually confirm whether the loaded condition falls within the CG envelope. The table method uses a computation form to sum weights and moments numerically and compares the resulting CG against published limits. Both should produce the same result.', 'Mixing units — such as moment versus moment divided by 1,000 — between the two methods, leading to a plotting or calculation error.', 'Consistency and accuracy using whichever method the applicant''s own aircraft''s POH primarily provides.', 'Area of Operation V, Task A — Performance and Limitations (Skill, Knowledge).', 'Know your specific aircraft''s actual method well enough to use it quickly and correctly under checkride pressure.', false, null, 22),
  ('perf-24', 'performance', 'What is ground effect, and how does it affect takeoff and landing?', 'Ground effect is a reduction in induced drag, along with some change in lift, experienced when flying within roughly one wingspan of the surface. It can allow an aircraft to become airborne before reaching a normal climb speed, then settle back if not properly accelerated once climbing out of ground effect, and can also cause floating during landing.', 'Mistaking a premature liftoff enabled by ground effect for adequate climb performance, risking a stall or settling back onto the runway once out of ground effect.', 'Whether the applicant connects ground effect to specific real risks — not just the definition itself.', 'Area of Operation V, Task A — Performance and Limitations (Knowledge). Cross-references Area IV, Takeoffs and Landings.', 'A soft-field takeoff technique deliberately uses ground effect — know why that specific technique actually works.', false, null, 23),
  ('perf-25', 'performance', 'What is the difference between Vx (best angle-of-climb) and Vy (best rate-of-climb)?', 'Vx gives the greatest altitude gain over the shortest horizontal distance, used for obstacle clearance after takeoff. Vy gives the greatest altitude gain over the shortest time, used for a normal climb to altitude. Vx is typically slower than Vy, and the two converge as density altitude increases.', 'Using Vy when obstacle clearance is actually the priority, or not knowing that Vx and Vy converge at higher density altitudes.', 'Whether the applicant selects the correct climb speed for the correct real-world scenario.', 'Area of Operation V, Task A — Performance and Limitations (Knowledge).', 'A short or obstructed-runway departure is exactly when knowing Vx from memory — not looked up — matters.', false, null, 24),
  ('perf-26', 'performance', 'How does altitude affect true airspeed (TAS) relative to indicated airspeed (IAS) for a constant power setting?', 'As altitude increases, air density decreases, so for the same indicated airspeed the aircraft is actually moving faster through the air — TAS increases roughly 2% per 1,000 feet above IAS. This is why performance and fuel planning use TAS, not IAS, for cross-country calculations.', 'Using indicated airspeed directly in a groundspeed or time-en-route calculation without first converting to true airspeed.', 'Correct sequencing — IAS to TAS to groundspeed — in the flight planning process.', 'Area of Operation V, Task A — Performance and Limitations (Knowledge). Cross-references Area IX, Task A.', 'This conversion directly affects the time and fuel estimates on every real cross-country nav log.', false, null, 25),
  ('perf-27', 'performance', 'How can installing additional equipment affect an aircraft''s useful load and weight and balance?', 'Adding equipment — avionics or other STC''d modifications — changes the aircraft''s empty weight and CG, requiring an updated weight and balance report and equipment list. Failing to account for this can result in exceeding limits with a load that used to be legal before the modification.', 'Relying on an outdated weight and balance report after equipment changes have actually been made to the aircraft.', 'Whether the applicant checks that the weight and balance data being used matches the aircraft''s current configuration.', 'Area of Operation V, Task A / Area I, Task B — Performance and Limitations, Airworthiness Requirements (Knowledge).', 'Rental fleets are updated over time — always verify you''re using the current weight and balance sheet for that specific tail number.', false, null, 26),
  ('perf-28', 'performance', 'What real-world margin should a pilot add beyond published short-field or soft-field performance numbers?', 'Published performance numbers assume a new aircraft, level paved dry runway, and precise test-pilot technique. Real-world margin should account for pilot proficiency, actual runway surface condition, actual (not forecast) wind, and aircraft condition — treating the chart number as a minimum, not an expected outcome.', 'Planning a short-field departure using the chart''s exact published distance with no personal safety margin added.', 'Whether the applicant applies genuine real-world judgment on top of the raw chart number, connecting Knowledge to Risk Management.', 'Area of Operation V, Task A — Performance and Limitations (Risk Management).', 'Build a personal margin — such as 1.5 times the published distance — as a genuine personal minimum for short-field operations.', false, null, 27),
  -- ═════════════════════ AEROMEDICAL FACTORS, extending to 16 (+8, first expansion since v5) ═════════════════════

  ('aeromed-9', 'aeromedical', 'What causes ear and sinus block (barotrauma) during flight, and how can it be prevented?', 'Barotrauma occurs when pressure cannot equalize between the middle ear or sinuses and the surrounding cabin pressure, typically during descent, and is worsened by congestion from a cold or allergies. Prevention includes the Valsalva maneuver, swallowing, or yawning — or simply not flying while significantly congested.', 'Attempting to "fly through" significant congestion, risking a painful and potentially injurious block during descent.', 'Whether the applicant treats congestion as a real IMSAFE illness factor, not a minor inconvenience to push through.', 'Area of Operation VII, Task A — Aeromedical Factors (Knowledge, Risk Management).', 'A common, entirely avoidable in-flight discomfort — postponing a flight due to a bad cold is a legitimate, defensible go/no-go decision.', false, null, 56),
  ('aeromed-10', 'aeromedical', 'What restrictions apply to flying after scuba diving?', 'To avoid decompression sickness, pilots should wait at least 12 hours after a dive not requiring decompression stops, and at least 24 hours after a dive that did require decompression stops, before flying to altitude.', 'Assuming a single brief waiting period applies regardless of dive profile, or forgetting the longer window required after a decompression-stop dive.', 'Correct recall of both waiting periods, not just a single general number.', 'Area of Operation VII, Task A — Aeromedical Factors (Knowledge).', 'Directly relevant for pilots who scuba dive on the same trip during which they intend to fly.', false, null, 57),
  ('aeromed-11', 'aeromedical', 'How does dehydration affect pilot performance, and why is it a specific concern in flight?', 'Dehydration degrades cognitive function, increases fatigue, and can worsen susceptibility to hypoxia. The low-humidity environment of an aircraft cabin, especially at altitude, accelerates fluid loss compared to a typical day on the ground.', 'Not recognizing the cabin''s low humidity as an accelerating factor, treating hydration no differently than on any ground-based day.', 'Whether the applicant connects a seemingly minor factor — hydration — to real cognitive performance risk.', 'Area of Operation VII, Task A — Aeromedical Factors (Knowledge, Risk Management).', 'Bring water on longer flights — a simple, concrete personal-minimums habit worth adopting.', false, null, 58),
  ('aeromed-12', 'aeromedical', 'How does night vision physiology affect a pilot''s ability to see at night?', 'Rod cells, used for low-light vision, are concentrated outside the central fovea, so off-center viewing is more effective at night than staring directly at a dim object. Rods take roughly 20–30 minutes to fully dark-adapt, and this adaptation is lost quickly when exposed to bright light.', 'Staring directly at a dim object at night rather than scanning slightly off-center, or exposing the eyes to bright cockpit light and expecting instant readaptation.', 'Applied, practical knowledge — off-center viewing and protecting dark adaptation — not just the rods-and-cones definition.', 'Area of Operation VII, Task A — Aeromedical Factors (Knowledge, Risk Management).', 'Use red or dimmed cockpit lighting at night specifically to preserve dark adaptation.', false, null, 59),
  ('aeromed-13', 'aeromedical', 'What general guidance applies to taking over-the-counter (OTC) medications before flight?', 'Many common OTC medications — antihistamines, sleep aids, and some cold or allergy medications — carry drowsiness or impairment warnings that make them inappropriate before flight. When in doubt, a pilot should consult an Aviation Medical Examiner rather than assume any given medication is safe to fly on.', 'Assuming "over-the-counter" automatically implies safe for flight, since prescription status alone doesn''t determine flight safety.', 'Whether the applicant knows to check, rather than assume, before taking any medication before flying.', 'Area of Operation VII, Task A — Aeromedical Factors (Knowledge, Risk Management).', 'Apply this specifically to genuinely common situations — allergy season, a minor cold — where an OTC medication might seem like an easy fix.', false, null, 60),
  ('aeromed-14', 'aeromedical', 'What is motion sickness, and what factors contribute to it during flight training?', 'Motion sickness results from a mismatch between visual, vestibular (inner ear), and proprioceptive sensory input, and is common early in flight training, typically diminishing with experience. Contributing factors include maneuvering flight, turbulence, anxiety, and poor cabin ventilation or heat.', 'Assuming motion sickness reflects a lack of aptitude for flying, rather than a common and usually temporary early-training experience.', 'Whether the applicant understands this as normal and manageable, connecting to genuine self-assessment rather than embarrassment.', 'Area of Operation VII, Task A — Aeromedical Factors (Knowledge).', 'Simple mitigations — fresh air, looking at the horizon, avoiding a heavy meal before maneuvers — genuinely help most new students.', false, null, 61),
  ('aeromed-15', 'aeromedical', 'How does cockpit noise exposure relate to pilot fatigue and long-term hearing health?', 'Prolonged cockpit noise exposure contributes to fatigue and can cause long-term hearing damage. A quality headset with adequate noise attenuation, passive or active, reduces both fatigue and hearing risk over the course of a flying career.', 'Treating hearing protection as a comfort preference rather than a genuine long-term health and fatigue-management factor.', 'Whether the applicant connects equipment choices, like headset quality, to genuine aeromedical wellbeing.', 'Area of Operation VII, Task A — Aeromedical Factors (Knowledge).', 'Cumulative noise exposure over a flying career is a real, measurable long-term health consideration.', false, null, 62),
  ('aeromed-16', 'aeromedical', 'Why must a pilot self-ground for a condition even if it doesn''t rise to the level of requiring FAA medical certificate action?', 'The regulatory medical certificate standard is a floor, not a real-time fitness check. 14 CFR 61.53 requires a pilot not to act as PIC while they know, or have reason to know, of any medical deficiency — even a temporary one, like an illness or medication effect — that would make them unable to safely operate the aircraft, independent of whether their medical certificate itself remains technically valid.', 'Believing a currently valid medical certificate alone is sufficient justification to fly on any given day, regardless of how the pilot actually feels.', 'Whether the applicant understands 61.53 as a continuous, self-imposed obligation distinct from certificate validity.', 'Area of Operation VII, Task A — Aeromedical Factors (Risk Management).', 'This regulation is the actual legal backbone of the entire IMSAFE habit — know the rule behind the practice.', false, null, 63),
  -- ═════════════════════ CROSS-COUNTRY PLANNING, extending to 33 (+8) ═════════════════════

  ('xc-26', 'crosscountry', 'Is the definition of "night" the same for logging, aircraft lighting, and passenger currency purposes?', 'No. "Night" for logbook purposes and for aircraft lighting requirements (such as position lights) is sunset to sunrise. Night currency for carrying passengers, however, uses a narrower window: one hour after sunset to one hour before sunrise.', 'Assuming a single definition of "night" applies uniformly across logging, lighting, and currency purposes.', 'Whether the applicant knows all three definitions are distinct and tied to different regulatory purposes.', 'Area of Operation I, Task A / Area IX, Task A — Pilot Qualifications, Navigation Systems and Flight Planning (Knowledge).', 'Matters directly when planning a flight that departs or arrives near dusk — know which "night" clock is actually running.', false, null, 25),
  ('xc-27', 'crosscountry', 'What is chart currency, and why does it matter for cross-country planning?', 'Sectional charts are updated on a periodic cycle, typically every six months, and can become outdated regarding tower frequencies, obstacles, TFRs, and airspace changes. Pilots should verify they''re using a current chart, whether paper or an EFB database, before every flight.', 'Using an expired paper chart or an out-of-date EFB database, missing a recently added obstacle or airspace change.', 'Whether the applicant treats chart currency as an active preflight check rather than a background assumption.', 'Area of Operation IX, Task A — Navigation Systems and Flight Planning (Knowledge).', 'EFB apps typically flag an expired chart or database — don''t dismiss that warning without checking it.', false, null, 26),
  ('xc-28', 'crosscountry', 'What makes a good visual checkpoint when planning a cross-country route?', 'A good checkpoint is a distinctive, easily identifiable feature from the air — a lake, a town, or a highway intersection — spaced at reasonable intervals, commonly every 10 to 20 nautical miles, to allow timely position and groundspeed confirmation.', 'Selecting checkpoints that are difficult to distinguish from the air, or spacing them too far apart to catch a navigation error early.', 'Practical judgment in checkpoint selection applied to the applicant''s own planned route.', 'Area of Operation IX, Task A — Navigation Systems and Flight Planning (Skill, Knowledge).', 'Often reviewed directly against the applicant''s actual submitted cross-country plan during the oral exam.', false, null, 27),
  ('xc-29', 'crosscountry', 'How is wind correction angle calculated, and why is it necessary?', 'Wind correction angle is the angular difference between true course and true heading needed to compensate for wind drift, calculated using a wind triangle, manually with an E6B or via an EFB. It''s necessary because flying the course heading directly, uncorrected, would drift the aircraft off its intended ground track.', 'Confusing heading — where the nose points, corrected for wind — with course — the intended ground track — and conflating the two on a nav log.', 'Whether the applicant maintains the correct heading, course, and track distinction throughout a nav log.', 'Area of Operation IX, Task A — Navigation Systems and Flight Planning (Knowledge, Skill).', 'Crosswind legs make this distinction immediately, practically obvious — small planning errors compound into real position error.', false, null, 28),
  ('xc-30', 'crosscountry', 'How do you verify actual groundspeed in flight against planned groundspeed, and what should you do if they don''t match?', 'Compare actual time between checkpoints to planned time, or use GPS groundspeed directly. If significantly different from the plan, recalculate fuel and time-en-route for the remaining legs, and consider whether the difference affects fuel reserves or requires a plan change.', 'Noticing a groundspeed discrepancy but not actually recalculating its downstream fuel and time impact for the rest of the flight.', 'Whether the applicant treats an in-flight discrepancy as something requiring active reassessment, not passive noting.', 'Area of Operation IX, Task A — Navigation Systems and Flight Planning (Skill, Risk Management).', 'An unexpectedly strong headwind discovered mid-flight is exactly the real scenario that should trigger this recalculation.', false, null, 29),
  ('xc-31', 'crosscountry', 'What common types of Temporary Flight Restrictions (TFRs) affect general aviation pilots, and what should be checked for each?', 'Common types include VIP movement TFRs, tied to travel of protected persons and often with little advance notice; disaster or hazard TFRs, such as wildfire response areas; and recurring stadium or sporting-event TFRs. Each has specific published dimensions and altitude limits that must be checked individually.', 'Checking for TFRs once during initial planning and not rechecking closer to departure, when VIP-type TFRs especially can appear with very little notice.', 'Awareness of multiple TFR categories and the importance of rechecking close to actual departure time.', 'Area of Operation IX, Task A — Navigation Systems and Flight Planning (Risk Management).', 'A Sunday cross-country flight near an NFL stadium is a textbook, entirely avoidable TFR bust if not checked specifically.', false, null, 30),
  ('xc-32', 'crosscountry', 'How should airspace and terrain factor into overall route selection, not just altitude selection?', 'Route selection should weigh avoiding unnecessary transits of busy Class B or C airspace when a reasonable alternate routing exists, and staying within glide range of suitable landing areas over inhospitable terrain where practical — balancing the most direct route against these genuine risk-reduction considerations.', 'Always planning the shortest straight-line route regardless of the airspace or terrain it crosses, without considering a slightly longer, lower-risk alternative.', 'Whether the applicant weighs route efficiency against genuine risk factors, rather than treating "shortest" as automatically "best."', 'Area of Operation IX, Task A — Navigation Systems and Flight Planning (Risk Management).', 'A route that follows a highway or valley, even if slightly longer, can be a meaningfully safer choice over remote terrain in a single-engine trainer.', false, null, 31),
  ('xc-33', 'crosscountry', 'What communication frequencies and services should be planned for along a cross-country route?', 'Plan relevant frequencies in advance: Flight Service or Flight Watch for en route weather updates, ATC facility frequencies for flight following, and destination airport frequencies — tower, CTAF, and ATIS or AWOS — noted directly on the flight plan rather than looked up reactively in flight.', 'Waiting until arrival to look up the destination''s frequencies, adding unnecessary workload during a busier phase of flight.', 'Whether the applicant''s actual submitted plan reflects this preparation, not just a general awareness that it''s a good idea.', 'Area of Operation IX, Task A — Navigation Systems and Flight Planning (Knowledge, Skill).', 'A well-prepared nav log with frequencies pre-filled reduces cockpit workload exactly when task saturation risk is highest, during arrival and descent.', false, null, 32),
  -- ═════════════════════ EMERGENCY OPERATIONS, extending to 16 (+8, first expansion since v5) ═════════════════════

  ('emerg-9', 'emergency', 'What is the general procedure for an in-flight engine fire?', 'Follow the aircraft''s specific checklist, but the general sequence typically includes mixture to idle cutoff, fuel selector off, fuel pump off, and cabin heat off — to avoid drawing smoke into the cabin — followed by a forced landing, since an engine fire is not generally something to attempt to fly through toward a distant airport.', 'Leaving cabin heat on during an engine fire response, which can draw smoke or fumes directly into the cabin.', 'Correct, aircraft-specific sequencing, with particular attention to the cabin heat detail.', 'Area of Operation X, Task A — Emergency Procedures (Knowledge, Skill).', 'Memorize your specific aircraft''s engine fire checklist cold — this is not one to read for the first time during the actual emergency.', true, null, 72),
  ('emerg-10', 'emergency', 'What is the general procedure for an in-flight electrical fire?', 'Turn off the master switch and all electrical equipment to isolate the source, use the fire extinguisher if available and needed, ventilate the cabin per aircraft-specific guidance if smoke is present, and land as soon as practical — restoring only essential equipment selectively if genuinely required for the landing.', 'Leaving all electrical equipment on while trying to identify the specific source, rather than isolating the whole system first.', 'Whether the applicant''s default instinct is to isolate the system broadly first, rather than troubleshooting item by item during an active fire.', 'Area of Operation X, Task A — Emergency Procedures (Knowledge, Skill).', 'Know exactly where your specific aircraft''s fire extinguisher is located and how to use it before you ever need to find out under stress.', true, null, 73),
  ('emerg-11', 'emergency', 'What should a pilot do if a door unexpectedly opens in flight?', 'In most light training aircraft, an open door in flight does not significantly affect controllability or performance. The correct response is to maintain aircraft control, verify airspeed and configuration remain normal, and land normally rather than attempting a risky in-flight fix.', 'Becoming startled and attempting an unsafe in-flight maneuver, such as reaching for the door or over-controlling the aircraft, instead of simply continuing to fly it.', 'Whether the applicant''s default instinct is to aviate first, even for a startling but usually low-severity event.', 'Area of Operation X, Task A — Emergency Procedures (Risk Management).', 'A genuinely common, low-severity event — knowing in advance that it''s mostly a non-event prevents an unnecessary overreaction.', true, null, 74),
  ('emerg-12', 'emergency', 'What should a pilot do if they experience a stuck microphone (transmitter) in flight?', 'A stuck mic can block the frequency for other aircraft and ATC. Try cycling the push-to-talk switch, check for a jammed headset connector, and try an alternate radio if equipped; be aware ATC or other aircraft may need to use light gun signals or another frequency to communicate if the block persists.', 'Not recognizing the symptom — an inability to hear replies, or reports from others of a blocked frequency — and continuing to attempt normal calls without troubleshooting the stuck switch.', 'Whether the applicant recognizes this specific, less commonly discussed failure mode.', 'Area of Operation X, Task A — Emergency Procedures (Knowledge).', 'An underrated real-world nuisance emergency — a stuck mic disrupts the entire frequency, not just the affected flight.', true, null, 75),
  ('emerg-13', 'emergency', 'What is the appropriate response to unexpectedly encountering structural icing in flight?', 'Exit the icing conditions immediately — typically by descending to warmer air, turning back toward known ice-free conditions, or climbing above a thin cloud layer if performance allows. Do not continue forward into icing conditions hoping they improve, and land as soon as practical once clear.', 'Continuing forward into icing conditions to "get through it faster," rather than reversing course or changing altitude immediately toward known better conditions.', 'Whether the applicant''s first instinct is to exit immediately in the most reliable direction, usually back the way they came, rather than pressing on.', 'Area of Operation X, Task A — Emergency Procedures (Risk Management).', 'For a non-deiced trainer, this decision needs to happen at the very first sign of ice accumulation, not after it becomes severe.', true, null, 76),
  ('emerg-14', 'emergency', 'What is the distinction between fuel exhaustion and fuel starvation, and why does it matter?', 'Fuel exhaustion means the aircraft has genuinely run out of usable fuel entirely. Fuel starvation means fuel is still available onboard but isn''t reaching the engine — from an incorrect tank selection, a blocked line, or a mismanaged fuel selector. The distinction matters because starvation may be correctable in flight, while exhaustion generally is not.', 'Assuming any fuel-related engine stoppage is unrecoverable, missing the chance to correct a starvation scenario simply by switching tanks or checking the selector.', 'Whether the applicant would actually check fuel selector position and switch tanks as an immediate troubleshooting step.', 'Area of Operation X, Task A — Emergency Procedures (Knowledge, Skill).', 'One of the most common, entirely preventable causes of engine failure in light aircraft, through both careful planning and in-flight vigilance.', true, null, 77),
  ('emerg-15', 'emergency', 'If you inadvertently fly into IMC as a VFR-only pilot, what is the recommended immediate response?', 'Immediately establish and maintain a wings-level attitude using the attitude indicator, resist the urge to make a rushed or steep turn, communicate with ATC for help if able, and once stabilized, initiate a gentle standard-rate turn back toward known VFR conditions — trusting instruments over physical sensation throughout.', 'Attempting a rushed, steep turn back immediately upon entering IMC, a response strongly associated with loss-of-control accidents from spatial disorientation.', 'Whether the applicant''s plan prioritizes stabilizing on instruments first, before any turn is attempted.', 'Area of Operation X, Task A — Emergency Procedures (Risk Management). Connects directly to spatial disorientation content in Area VII.', 'Unintentional VFR-into-IMC remains one of general aviation''s leading fatal accident causes — this rehearsed sequence is a genuine lifesaving skill.', true, null, 78),
  ('emerg-16', 'emergency', 'What is a pilot''s responsibility after experiencing a near midair collision (NMAC)?', 'While not mandatory, pilots are strongly encouraged to file a Near Midair Collision report with the FAA as soon as possible after landing, providing details to help identify causal factors and improve safety. ATC should also be notified at the time if the event occurs within controlled airspace or while receiving services.', 'Assuming a near miss with no actual contact or apparent violation carries no reporting value or isn''t worth the effort.', 'Understanding that voluntary reporting is a genuinely valued part of the aviation safety system, not a punitive process.', 'Area of Operation X, Task A — Emergency Procedures (Knowledge, Risk Management).', 'NMAC reports, along with the broader ASRS program, directly contribute to real safety improvements — participating is a professional norm.', true, null, 79);
